window.firmwareModuleFiles = {"a1.ino":"// Transmissions\nif (Stage_Con) {module_transmission(Stage_, Stage_Button, ONE_BYTE, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Stage_Con){Stage_Action();}\n\n// Action\nvoid Stage_Action() {\n  // Stage Button\n  if (Stage_Button[0] != Stage_STATE) {\n    Stage_STATE = Stage_Button[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setSimpitAction(Stage_STATE & 1, STAGE_ACTION, Stage_flag, simpitActivateAction);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setKey(Stage_Button[0] & 1, Stage_Stage, Stage_flag);\n    }\n  }\n  Stage_LAST = Stage_STATE;\n}\n\n// Keyboard Emulation\n  #define Stage_Stage                         ' '\n","a2.ino":"// Transmissions\nif (Abort_Con) {module_transmission(Abort_, Abort_Button, ONE_BYTE, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Abort_Con){Abort_Action();}\n\n// Action\nvoid Abort_Action() {\n  // Abort Button\n  if (Abort_Button[0] != Abort_STATE) {\n    Abort_STATE = Abort_Button[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setSimpitAction(Abort_STATE & 1, ABORT_ACTION, Abort_flag, simpitActivateAction);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setKey(Abort_Button[0] & 1, Abort_Abort, Abort_flag);\n    }\n  }\n  Abort_LAST = Abort_STATE;\n}\n\n// Keyboard Emulation\n  #define Abort_Abort                         KEY_BACKSPACE\n","a3.ino":"// Transmissions\nif (Executive_Actions_Con) {module_transmission(Executive_Actions_, Executive_Actions, ONE_BYTE, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Executive_Actions_Con){Executive_Actions_Action();}\n\n// Action\nvoid Executive_Actions_Action() {\n  if (Executive_Actions[0] != Executive_Actions_STATE) {\n    Executive_Actions_STATE = Executive_Actions[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setSimpitAction(Executive_Actions_STATE & 1, STAGE_ACTION, Executive_Actions_flag[0], simpitActivateAction);\n      setSimpitAction(Executive_Actions_STATE & 2, ABORT_ACTION, Executive_Actions_flag[1], simpitActivateAction);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setKey(Executive_Actions_STATE & 1, Executive_Actions_Stage, Executive_Actions_flag[0]);\n      setKey(Executive_Actions_STATE & 2, Executive_Actions_Abort, Executive_Actions_flag[1]);\n    }\n  }\n  Executive_Actions_LAST = Executive_Actions_STATE;\n}\n\n// Keyboard Emulation\n  #define Executive_Actions_Stage             ' '\n  #define Executive_Actions_Abort             KEY_BACKSPACE","a4.ino":"// Transmissions\nif (EA_Groups_Ctrl_Con) {module_transmission(EA_Groups_Ctrl_, EA_Groups_Ctrl, ONE_BYTE, EA_Groups_Dspl_, EA_Groups_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (EA_Groups_Ctrl_Con){EA_Groups_Action();}\n\n// Action Results\nconst int EA_Groups_List[5] = {1, 2, 3, 4, 5};\n\n// Action\nvoid EA_Groups_Action() {\n  if (EA_Groups_Ctrl[0] != EA_Groups_STATE) {\n    EA_Groups_STATE = EA_Groups_Ctrl[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      for (int i = 0; i < 5; i++) {\n        setSimpitAction(EA_Groups_STATE & 1<<i, EA_Groups_List[i], EA_Groups_flag[i], simpitToggleCAG);\n      }\n      setSimpitAction(EA_Groups_STATE & 32, STAGE_ACTION, EA_Groups_flag[5], simpitActivateAction);\n      setSimpitAction(EA_Groups_STATE & 64, ABORT_ACTION, EA_Groups_flag[6], simpitActivateAction);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 7; i++) {\n        setKey(EA_Groups_STATE & 1<<i, EA_Groups_Emulation_Keys[i], EA_Groups_flag[i]);\n      }\n    }\n  }\n  EA_Groups_LAST = EA_Groups_STATE;\n}\n\n// Message Handler\n        if (EA_Groups_Ctrl_Con) {\n          bool EA_Groups_Dspl_b[8] = {0,0,0,0,0,0,0,0};\n          for (int i = 0; i < 8; i++) {\n            EA_Groups_Dspl_b[i] = (myAG.is_action_activated(i+1));\n          }\n          for (int i = 0; i < 8; i++) {\n            bitWrite(EA_Groups_Dspl[0], i, EA_Groups_Dspl_b[i]);\n          }\n        }\n\n// Keyboard Emulation\n  #define EA_Groups_Stage                     ' '\n  #define EA_Groups_Abort                     KEY_BACKSPACE \n  #define EA_Groups_Action_Group_1            '1'\n  #define EA_Groups_Action_Group_2            '2'\n  #define EA_Groups_Action_Group_3            '3'\n  #define EA_Groups_Action_Group_4            '4'\n  #define EA_Groups_Action_Group_5            '5'\n  \n\n// definitions\n  const uint8_t EA_Groups_Emulation_Keys[7] = {\n    EA_Groups_Action_Group_1,\n    EA_Groups_Action_Group_2,\n    EA_Groups_Action_Group_3,\n    EA_Groups_Action_Group_4,\n    EA_Groups_Action_Group_5,\n    EA_Groups_Stage,\n    EA_Groups_Abort\n  };","a5.ino":"// Transmissions\nif (EA_Control_Ctrl_Con) {module_transmission(EA_Control_Ctrl_, EA_Control_Ctrl, ONE_BYTE, EA_Control_Dspl_, EA_Control_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (EA_Control_Ctrl_Con){EA_Control_Action();}\n\n// Action\nvoid EA_Control_Action() {\n  if (EA_Control_Ctrl[0] != EA_Control_STATE) {\n    EA_Control_STATE = EA_Control_Ctrl[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setSimpitAction(EA_Control_STATE & 1, LIGHT_ACTION, EA_Control_flag[0], simpitToggleAction);\n      setSimpitAction(EA_Control_STATE & 2, GEAR_ACTION, EA_Control_flag[1], simpitToggleAction);\n      setSimpitAction(EA_Control_STATE & 4, AP_STABILITYASSIST, EA_Control_flag[2], simpitSetSASMode);\n      setSimpitAction_Switch(EA_Control_STATE & 8, SAS_ACTION, EA_Control_flag[3], simpitActivateAction, simpitDeactivateAction);\n      setSimpitAction_Switch(EA_Control_STATE & 16, RCS_ACTION, EA_Control_flag[4], simpitActivateAction, simpitDeactivateAction);\n      setSimpitAction(EA_Control_STATE & 32, STAGE_ACTION, EA_Control_flag[5], simpitActivateAction);\n      setSimpitAction(EA_Control_STATE & 64, ABORT_ACTION, EA_Control_flag[6], simpitActivateAction);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setKey(EA_Control_STATE & 1, EA_Control_Light, EA_Control_flag[0]);\n      setKey(EA_Control_STATE & 2, EA_Control_Gear, EA_Control_flag[1]);\n      setKey(EA_Control_STATE & 4, EA_Control_Hold, EA_Control_flag[2]);\n      setKey_Switch(EA_Control_STATE & 8, EA_Control_SAS, EA_Control_flag[3]);\n      setKey_Switch(EA_Control_STATE & 16, EA_Control_RCS, EA_Control_flag[4]);\n      setKey(EA_Control_STATE & 32, EA_Control_Stage, EA_Control_flag[5]);\n      setKey(EA_Control_STATE & 64, EA_Control_Abort, EA_Control_flag[6]);\n    }\n  }\n  EA_Control_LAST = EA_Control_STATE;\n}\n\n// Keyboard Emulation\n  #define EA_Control_Stage                    ' '\n  #define EA_Control_Abort                    KEY_BACKSPACE\n  #define EA_Control_Light                    'u'\n  #define EA_Control_Gear                     'g'\n  #define EA_Control_Hold                     '1'\n  #define EA_Control_SAS                      't'\n  #define EA_Control_RCS                      'r'\n\n// definitions\n  const uint8_t EA_Control_Emulation_Keys[8] = {\n    EA_Control_Light,\n    EA_Control_Gear,\n    EA_Control_Hold,\n    EA_Control_SAS,\n    EA_Control_RCS,\n    EA_Control_Stage,\n    EA_Control_Abort\n  };","b1.ino":"// Transmissions  \nif (Time_Ctrl_Con) {module_transmission(Time_Ctrl_, Time_Ctrl, ONE_BYTE, Time_Dspl_, Time_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (Time_Ctrl_Con){Time_Action();}\n\n// Action Results\nuint8_t Time_List[8] = {\n  KSP_MOD_KEY2,\n  0,        // NULL\n  '.',\n  ',',\n  '/',\n  KEY_ESC,\n  KEY_F5,\n  KEY_F9,\n};\n\n// Action\nvoid Time_Action() {\n  if (Time_Ctrl[0] != Time_STATE) {\n    Time_STATE = Time_Ctrl[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setKey(Time_STATE & 1, Time_List[0], Time_flag[0]);\n      setSimpitAction(Time_STATE & 2, 0, Time_flag[1], simpitSendTimewarp);\n      for (int i = 2; i < 7; i++) {\n        setSimpitAction(Time_STATE & 1<<i, Time_List[i], Time_flag[i], tapKey);\n      }\n      setKey(Time_STATE & 128, Time_List[7], Time_flag[7]);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 8; i++) {\n        setKey(Time_STATE & 1<<i, Time_Emulation_Keys[i], Time_flag[i]);\n      }\n    }\n  }\n  Time_LAST = Time_STATE;\n}\n\n// Keyboard Emulation\n  #define Time_Phys_Tw                        'p'\n  #define Time_To_Mnvr                        '1'\n  #define Time_Timewarp_Up                    '.'\n  #define Time_Timewarp_Down                  ','\n  #define Time_Stop_Tw                        '/'\n  #define Time_Pause                          'e'\n  #define Time_Save                           's'\n  #define Time_Load                           'l'\n\n// definitions\n  const uint8_t Time_Emulation_Keys[8] = {\n    Time_Phys_Tw,\n    Time_To_Mnvr,\n    Time_Timewarp_Up,\n    Time_Timewarp_Down,\n    Time_Stop_Tw,\n    Time_Pause,\n    Time_Save,\n    Time_Load\n  };","b2.ino":"// Transmissions\nif (Navigation_Con) {module_transmission(Navigation_, Navigation, ONE_BYTE, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Navigation_Con){Navigation_Action();}\n\n// Action Results\nuint8_t Nav_List[8] = {\n  Nav_KSP1_KSP2,\n  '[',\n  KEY_TAB,\n  ']',\n  KEY_TAB,\n  0,        // NULL\n  'm',\n  'y',      // Was Numpad .\n};\n\n// Action\nvoid Navigation_Action() {\n  if (Navigation[0] != Navigation_STATE) {\n    Navigation_STATE = Navigation[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setSimpitAction(Navigation_STATE & 1, Nav_List[0], Navigation_flag[0], tapKey);\n      setSimpitAction(Navigation_STATE & 2, Nav_List[1], Navigation_flag[1], tapKey);\n\n      if (Navigation_STATE & 4) {\n        Keyboard.press(KSP_MOD_KEY);\n        delay(50);\n        tapKey(Nav_List[2]);\n        delay(50);\n        Keyboard.release(KSP_MOD_KEY);\n      }\n\n      setSimpitAction(Navigation_STATE & 8, Nav_List[3], Navigation_flag[3], tapKey);\n      setSimpitAction(Navigation_STATE & 16, Nav_List[4], Navigation_flag[4], tapKey);\n      setSimpitAction(Navigation_STATE & 32, Nav_List[5], Navigation_flag[5], simpitCycleNavBallMode);\n\n      if((Navigation_STATE & 64) && !Navigation_Map_flag){\n        tapKey(Nav_List[6]);\n        if (!Navigation_NAV_flag) {\n          tapKey(Nav_List[7]);\n        }\n        Navigation_Map_flag = true;\n      }\n      if(!(Navigation_STATE & 64) && Navigation_Map_flag){\n        tapKey(Nav_List[6]);\n        if (!Navigation_NAV_flag) {\n          tapKey(Nav_List[7]);\n        }\n        Navigation_Map_flag = false;\n      }\n\n      setSimpitAction_Switch(Navigation_STATE & 128, Nav_List[7], Navigation_NAV_flag, tapKey, tapKey);\n\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 6; i++) {\n        setKey(Navigation_STATE & 1<<i, Navigation_Emulation_Keys[i], Navigation_flag[i]);\n      }\n      setKey_Switch(Navigation_STATE & 64, Navigation_Map, Navigation_flag[6]);\n      setKey_Switch(Navigation_STATE & 128, Navigation_Nav, Navigation_flag[7]);\n    }\n  }\n  Navigation_LAST = Navigation_STATE;\n}\n\n// Keyboard Emulation\n  #define Navigation_Map                      'm'\n  #define Navigation_Cycle_Map_Up             KEY_TAB\n  #define Navigation_Cycle_Map_Down           KEY_TAB\n  #define Navigation_Map_Return               '`'\n  #define Navigation_Nav                      '.'\n  #define Navigation_Cycle_Nav                '1'\n  #define Navigation_Cycle_Ship_Up            ']'\n  #define Navigation_Cycle_Ship_Down          '['\n\n// definitions\n  const uint8_t Navigation_Emulation_Keys[8] = {\n    Navigation_Map_Return,\n    Navigation_Cycle_Ship_Down,\n    Navigation_Cycle_Map_Up,\n    Navigation_Cycle_Ship_Up,\n    Navigation_Cycle_Map_Down,\n    Navigation_Cycle_Nav,\n    Navigation_Map,\n    Navigation_Nav\n  };","b3.ino":"// Transmissions\nif (Navigation_Time_Ctrl_Con) {module_transmission(Navigation_Time_Ctrl_, Navigation_Time_Ctrl, ONE_BYTE, Time_Dspl_, Time_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (Navigation_Time_Ctrl_Con){Navigation_Time_Action();}\n\n// Action Results\nuint8_t Navigation_Time_List[8] = {\n  KEY_LEFT_ALT,\n  '1',\n  '.',\n  ',',\n  '/',\n  ']',\n  '`',\n  'm'\n};\n\n// Action\nvoid Navigation_Time_Action() {\n  if (Navigation_Time_Ctrl[0] != Navigation_Time_STATE) {\n    Navigation_Time_STATE = Navigation_Time_Ctrl[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      setKey(Navigation_Time_STATE & 1, Navigation_Time_List[0], Navigation_Time_flag[0]);\n      setSimpitAction(Navigation_Time_STATE & 2, 0, Navigation_Time_flag[1], simpitSendTimewarp);\n      for (int i = 2; i <= 6; i++) {\n        setSimpitAction(Navigation_Time_STATE & 1<<i, Navigation_Time_List[i], Navigation_Time_flag[i], tapKey);\n      }\n      setSimpitAction_Switch(Navigation_Time_STATE & 128, Navigation_Time_List[7], Navigation_Time_flag[7], tapKey, tapKey);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 7; i++) {\n        setKey(Navigation_Time_STATE & 1<<i, Navigation_Time_Emulation_Keys[i], Navigation_Time_flag[i]);\n      }\n      setKey_Switch(Navigation_Time_STATE & 128, Navigation_Map, Navigation_Time_flag[7]);\n    }\n  }\n  Navigation_Time_LAST = Navigation_Time_STATE;\n}\n\n// Keyboard Emulation\n  #define Navigation_Time_Map                 'm'\n  #define Navigation_Time_Map_Return          '`'\n  #define Navigation_Time_Cycle_Ship_Up       ']'\n  #define Navigation_Time_To_Mnvr             '1'\n  #define Navigation_Time_Phys_Tw             KEY_LEFT_ALT\n  #define Navigation_Time_Timewarp_Up         '.'\n  #define Navigation_Time_Timewarp_Down       ','\n  #define Navigation_Time_Stop_Tw             '/'\n\n// definitions\n  const uint8_t Navigation_Time_Emulation_Keys[8] = {\n    Navigation_Time_Phys_Tw,\n    Navigation_Time_To_Mnvr,\n    Navigation_Time_Timewarp_Up,\n    Navigation_Time_Timewarp_Down,\n    Navigation_Time_Stop_Tw,\n    Navigation_Time_Cycle_Ship_Up,\n    Navigation_Time_Map_Return,\n    Navigation_Time_Map,\n  };","b4.ino":"// Transmissions\nif (Util_Nav_Ctrl_Con) {module_transmission(Util_Nav_Ctrl_, Util_Nav_Ctrl, ONE_BYTE, EVA_Dspl_, EVA_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (Util_Nav_Ctrl_Con){Util_Nav_Action();}\n\n// Action Results\nuint8_t Util_Nav_List[8] = {\n  'b',\n  'f',\n  ' ',\n  'r',\n  'u',\n  ']',\n  0,\n  'm'\n};\n\n// Action\nvoid Util_Nav_Action() {\n  if (Util_Nav_Ctrl[0] != Util_Nav_STATE) {\n    Util_Nav_STATE = Util_Nav_Ctrl[0];\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (On_EVA) {\n        for (int i = 0; i < 5; i++) {\n          setSimpitAction(Util_Nav_STATE & 1<<i, Util_Nav_List[i], Util_Nav_flag[i], tapKey);\n        }\n      }\n      setSimpitAction(Util_Nav_STATE & 1<<5, Util_Nav_List[5], Util_Nav_flag[5], tapKey);\n      setSimpitAction(Util_Nav_STATE & 1<<6, Util_Nav_List[6], Util_Nav_flag[6], simpitCycleNavBallMode);\n      setSimpitAction_Switch(Util_Nav_STATE & 1<<7, Util_Nav_List[7], Util_Nav_flag[7], tapKey, tapKey);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 7; i++) {\n        setKey(Util_Nav_STATE & 1<<i, Util_Nav_Emulation_Keys[i], Util_Nav_flag[i]);\n      }\n    }\n  }\n  Util_Nav_LAST = Util_Nav_STATE;\n}\n\n// Keyboard Emulation\n  #define Utility_Board                       'b'\n  #define Utility_Grab                        'f'\n  #define Utility_Jump                        ' '\n  #define Utility_Jet                         'r'\n  #define Utility_Light                       'u'\n  #define Utility_Map                         'm'\n  #define Utility_Cycle_Ship                  ']'\n  #define Utility_Cycle_Nav                   '1'\n\n// definitions\n  const uint8_t Util_Nav_Emulation_Keys[8] = {\n    Utility_Board,\n    Utility_Grab,\n    Utility_Jump,\n    Utility_Jet,\n    Utility_Light,\n    Utility_Cycle_Ship,\n    Utility_Cycle_Nav,\n    Utility_Map,\n  };","b5.ino":"// Transmissions\nif (Util_Time_Ctrl_Con) {module_transmission(Util_Time_Ctrl_, Util_Time_Ctrl, ONE_BYTE, EVA_Dspl_, EVA_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (Util_Time_Ctrl_Con){Util_Time_Action();}\n\n// Action Results\nuint8_t Util_Time_List[8] = {\n  'b',\n  'f',\n  ' ',\n  'r',\n  'u',\n  KEY_F9,\n  KEY_F5,\n  KEY_ESC\n};\n\n// Action\nvoid Util_Time_Action() {\n  if (Util_Time_Ctrl[0] != Util_Time_STATE) {\n    Util_Time_STATE = Util_Time_Ctrl[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (On_EVA) {\n        for (int i = 0; i < 5; i++) {\n          setSimpitAction(Util_Time_STATE & 1<<i, Util_Time_List[i], Util_Time_flag[i], tapKey);\n        }\n      }\n      setSimpitAction_Switch(Util_Time_STATE & 1<<5, Util_Time_List[5], Util_Time_flag[5], tapKey, tapKey);\n      setSimpitAction(Util_Time_STATE & 1<<6, Util_Time_List[6], Util_Time_flag[6], tapKey);\n      setSimpitAction(Util_Time_STATE & 1<<7, Util_Time_List[7], Util_Time_flag[7], tapKey);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 7; i++) {\n        setKey(Util_Time_STATE & 1<<i, Util_Time_Emulation_Keys[i], Util_Time_flag[i]);\n      }\n    }\n  }\n  Util_Time_LAST = Util_Time_STATE;\n}\n\n// Keyboard Emulation\n  #define Utility_Time_Board                  'b'\n  #define Utility_Time_Grab                   'f'\n  #define Utility_Time_Jump                   ' '\n  #define Utility_Time_Jet                    'r'\n  #define Utility_Time_Light                  'u'\n  #define Utility_Time_Pause                  KEY_ESC\n  #define Utility_Time_Save                   KEY_F5\n  #define Utility_Time_Load                   KEY_F9\n\n// definitions\n  const uint8_t Util_Time_Emulation_Keys[8] = {\n    Utility_Time_Board,\n    Utility_Time_Grab,\n    Utility_Time_Jump,\n    Utility_Time_Jet,\n    Utility_Time_Light,\n    Utility_Time_Load,\n    Utility_Time_Save,\n    Utility_Time_Pause,\n  };","c1.ino":"// Transmissions\nif (LCD_Con) {LCD_transmission(LCD_, LCD_data);}\n\n// Message Handler\n    case LF_MESSAGE:\n      if (LCD_mode == 0) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage myLF;\n          myLF = parseResource(msg);\n          if (myLF.available) {\n            LCD_data[0] = String(map(myLF.available, 0, myLF.total, 0, 52));\n          } else {\n            LCD_data[0] = \"0\";\n          }\n        }\n      }\n      break;\n    \n    case OX_MESSAGE:\n      if (LCD_mode == 0) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage myOX;\n          myOX = parseResource(msg);\n          if (myOX.available) {\n            LCD_data[1] = String(map(myOX.available, 0, myOX.total, 0, 52));\n          } else {\n            LCD_data[1] = \"0\";\n          }\n        }\n      }\n      break;\n\n    case SF_MESSAGE:\n      if (LCD_mode == 0) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage mySF;\n          mySF = parseResource(msg);\n          if (mySF.available) {\n            LCD_data[2] = String(map(mySF.available, 0, mySF.total, 0, 52));\n          } else {\n            LCD_data[2] = \"0\";\n          }\n        }\n      }\n      break;\n\n    case ELECTRIC_MESSAGE:\n      if (LCD_mode == 0) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage myEC;\n          myEC = parseResource(msg);\n          if (myEC.available) {\n            LCD_data[3] = String(map(myEC.available, 0, myEC.total, 0, 52));\n          } else {\n            LCD_data[3] = \"0\";\n          }\n        }\n      }\n      break;\n\n    case XENON_GAS_MESSAGE:\n      if (LCD_mode == 0) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage myXE;\n          myXE = parseResource(msg);\n          if (myXE.available) {\n            LCD_data[4] = String(map(myXE.available, 0, myXE.total, 0, 52));\n          } else {\n            LCD_data[4] = \"0\";\n          }\n        }\n      }\n      break;\n\n    case MONO_MESSAGE:\n      if (LCD_mode == 0) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage myMP;\n          myMP = parseResource(msg);\n          if (myMP.available) {\n            LCD_data[5] = String(map(myMP.available, 0, myMP.total, 0, 52));\n          } else {\n            LCD_data[5] = \"0\";\n          }\n        }\n      }\n      break;\n\n    case APSIDES_MESSAGE:\n      if ((LCD_mode == 1) or (LCD_mode == 2) or (LCD_mode == 3)) {\n        if (msgSize == sizeof(apsidesMessage)) {\n          apsidesMessage myAps;\n          myAps = parseMessage<apsidesMessage>(msg);\n          String apo = String(myAps.apoapsis);\n          String peri = String(myAps.periapsis);\n          int stringLength = apo.length();\n          apo.remove(stringLength - 3, 3);\n          LCD_data[6] = apo;\n          stringLength = peri.length();\n          peri.remove(stringLength - 3, 3);\n          LCD_data[7] = peri;\n        }\n      }\n      break;\n\n    case APSIDESTIME_MESSAGE:\n      if ((LCD_mode == 1) or (LCD_mode == 2) or (LCD_mode == 3)) {\n        if (msgSize == sizeof(apsidesTimeMessage)) {\n          apsidesTimeMessage myAps;\n          myAps = parseMessage<apsidesTimeMessage>(msg);\n          String apo = String(myAps.apoapsis);\n          String peri = String(myAps.periapsis);\n          LCD_data[8] = apo;\n          LCD_data[9] = peri;\n        }\n      }\n      break;\n\n    case DELTAV_MESSAGE:\n      if ((LCD_mode == 1) or (LCD_mode == 2)) {\n        if (msgSize == sizeof(deltaVMessage)) {\n          deltaVMessage mydV;\n          mydV = parseMessage<deltaVMessage>(msg);\n          String dV = String(mydV.totalDeltaV);\n          int stringLength = dV.length();\n          dV.remove(stringLength - 3, 3);\n          LCD_data[5] = dV;\n        }\n      }\n      break;\n\n    case ALTITUDE_MESSAGE:\n      if (LCD_mode == 1) {\n        if (msgSize == sizeof(altitudeMessage)) {\n          altitudeMessage myAlt;\n          myAlt = parseMessage<altitudeMessage>(msg);\n          String sealevel = String(myAlt.sealevel);\n          String surface = String(myAlt.surface);\n          int stringLength = sealevel.length();\n          sealevel.remove(stringLength - 3, 3);\n          LCD_data[0] = sealevel;\n          stringLength = surface.length();\n          surface.remove(stringLength - 3, 3);\n          LCD_data[1] = surface;\n        }\n      }\n      break;\n\n    case VELOCITY_MESSAGE:\n      if (LCD_mode == 1) {\n        if (msgSize == sizeof(velocityMessage)) {\n          velocityMessage myVel;\n          myVel = parseMessage<velocityMessage>(msg);\n          String orbital = String(myVel.orbital);\n          String surface = String(myVel.surface);\n          String vertical = String(myVel.vertical);\n          int stringLength = orbital.length();\n          orbital.remove(stringLength - 3, 3);\n          LCD_data[2] = orbital;\n          stringLength = surface.length();\n          surface.remove(stringLength - 3, 3);\n          LCD_data[3] = surface;\n          stringLength = vertical.length();\n          vertical.remove(stringLength - 3, 3);\n          LCD_data[4] = vertical;\n        }\n      }\n      break;\n\n    case MANEUVER_MESSAGE:\n      if (LCD_mode == 2) {\n        if (msgSize == sizeof(maneuverMessage)) {\n          maneuverMessage myMnv;\n          myMnv = parseMessage<maneuverMessage>(msg);\n          String deltaVNextManeuver = String(myMnv.deltaVNextManeuver);\n          int stringLength = deltaVNextManeuver.length();\n          deltaVNextManeuver.remove(stringLength - 3, 3);\n          LCD_data[0] = deltaVNextManeuver;\n          \n          String timeToNextManeuver = String(myMnv.timeToNextManeuver);\n          stringLength = timeToNextManeuver.length();\n          timeToNextManeuver.remove(stringLength - 3, 3);\n          LCD_data[1] = timeToNextManeuver;\n          \n          String durationNextManeuver = String(myMnv.durationNextManeuver);\n          LCD_data[2] = durationNextManeuver;\n          \n          String deltaVTotal = String(myMnv.deltaVTotal);\n          stringLength = deltaVTotal.length();\n          deltaVTotal.remove(stringLength - 3, 3);\n          LCD_data[3] = deltaVTotal;\n        }\n      }\n      break;\n\n    case ORBIT_MESSAGE:\n      if (LCD_mode == 3) {\n        if (msgSize == sizeof(orbitInfoMessage)) {\n          orbitInfoMessage myOrb;\n          myOrb = parseMessage<orbitInfoMessage>(msg);\n          String semiMajorAxis = String(myOrb.semiMajorAxis);\n          int stringLength = semiMajorAxis.length();\n          semiMajorAxis.remove(stringLength - 3, 3);\n          LCD_data[0] = semiMajorAxis;\n          LCD_data[1] = String(myOrb.eccentricity);\n          LCD_data[2] = String(myOrb.inclination);\n          LCD_data[3] = String(myOrb.period);\n        }\n      }\n      break;","d1.ino":"// Transmissions\nif (EVA_Ctrl_Con) {module_transmission(EVA_Ctrl_, EVA_Ctrl, TWO_BYTES, EVA_Dspl_, EVA_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (EVA_Ctrl_Con){EVA_Action();}\n\n// Action Results\nuint8_t EVA_List[12] = {\n  'b',\n  'f',\n  ' ',\n  'r',\n  KEY_LEFT_SHIFT,\n  KEY_LEFT_CTRL,\n  'w',\n  'a',\n  's',\n  'd',\n  'u',\n  'p',\n};\n\n// Action\nvoid EVA_Action() {\n  EVA_combinedBytes = (EVA_Ctrl[1]*256) + EVA_Ctrl[0];\n  if (EVA_combinedBytes != EVA_STATE) {\n    EVA_STATE = EVA_combinedBytes;\n\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (On_EVA) {\n        for (int i = 0; i < 4; i++) {\n          setSimpitAction(EVA_STATE & 1<<i, EVA_List[i], EVA_flag[i], tapKey);\n        }\n        for (int i = 4; i < 11; i++) {\n          setSimpitAction_Switch(EVA_STATE & 1<<i, EVA_List[i], EVA_flag[i], tapKey, tapKey);\n        }\n        setSimpitAction((EVA_STATE & 1<<2) and (EVA_STATE & 1<<10), EVA_List[11], EVA_flag[11], tapKey);\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 11; i++) {\n        setKey(EVA_STATE & 1<<i, EVA_Emulation_Keys[i], EVA_flag[i]);\n      }\n    }\n  }\n  EVA_LAST = EVA_STATE;\n}\n\n// Message Handler\n    case EVA_MESSAGE:\n      if (EVA_Ctrl_Con || Util_Nav_Ctrl_Con || Util_Time_Ctrl_Con) {\n        if (msgSize == sizeof(resourceMessage)) {\n          resourceMessage myEVA;\n          myEVA = parseResource(msg);\n          if (myEVA.available) {\n            int myEVA_available = myEVA.available * 100.00;\n            int myEVA_total = myEVA.total * 100.00;\n            EVA_Dspl[0] = map(myEVA_available, 0, myEVA_total, 1, 10);\n            if (myEVA_available==0) {\n              EVA_Dspl[0] = 0;\n            }\n          }\n        }\n      }\n      break;\n\n// Keyboard Emulation\n  #define EVA_Board                           'b'\n  #define EVA_Grab                            'f'\n  #define EVA_Jump                            ' '\n  #define EVA_Jet                             'r'\n  #define EVA_Light                           'u'\n  #define EVA_Up                              KEY_LEFT_SHIFT\n  #define EVA_Down                            KEY_LEFT_CTRL\n  #define EVA_W                               'w'\n  #define EVA_A                               'a'\n  #define EVA_S                               's'\n  #define EVA_D                               'd'\n\n// definitions\n  const uint8_t EVA_Emulation_Keys[11] = {\n    EVA_Board,\n    EVA_Grab,\n    EVA_Jump,\n    EVA_Jet,\n    EVA_Up,\n    EVA_Down,\n    EVA_W,\n    EVA_A,\n    EVA_S,\n    EVA_D,\n    EVA_Light\n  };","e1.ino":"// Transmissions\nif (Camera_Con) {module_transmission(Camera_, Camera, TWO_BYTES, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Camera_Con){Camera_Action();}\n\n// Action Results\nconst int Camera_List[10] = {\n  KEY_F2,\n  KEY_F1,\n  '-',      // Was Numpad -\n  KEY_RIGHT_ARROW,\n  KEY_DOWN_ARROW,\n  KEY_UP_ARROW,\n  KEY_LEFT_ARROW,\n  '=',      // Was Numpad +\n  'c',\n  'v',\n};\n\n// Action\nvoid Camera_Action() {\n  Camera_combinedBytes = Camera[0] + (Camera[1]*256);\n  if (Camera_combinedBytes != Camera_STATE) {\n    Camera_STATE = Camera_combinedBytes;\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      for (int i = 0; i < 2; i++) {\n        setSimpitAction(Camera_STATE & 1<<i, Camera_List[i], Camera_flag[i], tapKey);\n      }\n      for (int i = 2; i < 8; i++) {\n        setKey(Camera_STATE & 1<<i, Camera_List[i], Camera_flag[i]);\n      }\n      for (int i = 8; i < 10; i++) {\n        setSimpitAction(Camera_STATE & 1<<i, Camera_List[i], Camera_flag[i], tapKey);\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 10; i++) {\n        setKey(Camera_STATE & 1<<i, Camera_Emulation_Keys[i], Camera_flag[i]);\n      }\n    }\n  }\n  Camera_LAST = Camera_STATE;\n}\n\n// Keyboard Emulation\n  #define Camera_UI                           KEY_F2\n  #define Camera_Screenshot                   KEY_F1\n  #define Camera_Minus                        '-'\n  #define Camera_Right                        KEY_RIGHT_ARROW\n  #define Camera_Down                         KEY_DOWN_ARROW\n  #define Camera_Left                         KEY_LEFT_ARROW\n  #define Camera_Up                           KEY_UP_ARROW\n  #define Camera_Plus                         '+'\n  #define Camera_IVA                          'c'\n  #define Camera_CycleCamera                  'v'\n\n// definitions\n  const uint8_t Camera_Emulation_Keys[10] = {\n    Camera_UI,\n    Camera_Screenshot,\n    Camera_Minus,\n    Camera_Right,\n    Camera_Down,\n    Camera_Left,\n    Camera_Up,\n    Camera_Plus,\n    Camera_IVA,\n    Camera_CycleCamera,\n  };","f1f2.ino":"// Transmissions\nif (Analog_Con) {module_transmission(Analog_, Analog, 8, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\nif (Analog_Throttle_Con) {module_transmission(Analog_Throttle_, Analog, 9, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Analog_Con or Analog_Throttle_Con){Analog_Action();}\n\n// Action\nvoid Analog_Action() {\n  if (Analog[0] != Analog_STATE) {\n    Analog_STATE = Analog[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (Analog[0] & 2) {\n        trimy = 0;\n        trimp = 0;\n        trimr = 0;\n        cruise_control = 0;\n        myWheel.throttle = 0;\n      }\n      if (Analog[0] & 4){ \n        if (Analog[0] & 1) {\n          brakes_lock = true;\n        } else {\n          brakes_lock = false;\n        }\n        if (!(currentActionStatus & BRAKES_ACTION)) {\n          mySimpit.activateAction(BRAKES_ACTION);\n        }\n      }\n      if (!(Analog[0] & 4) && (currentActionStatus & BRAKES_ACTION) && !(brakes_lock)){\n        mySimpit.deactivateAction(BRAKES_ACTION);\n      }\n      if (Analog[0] & 8) {\n        vehicleType = rover;\n      } else if (Analog[0] & 16) {\n        vehicleType = plane;\n      } else {\n        vehicleType = rocket;\n      }\n      if(Analog[0] & 32){\n        analog_mode = 1;\n      } else {\n        analog_mode = 0;\n      }\n      if (Analog_Con) {\n        if((Analog[0] & 64) && !(currentActionStatus & GEAR_ACTION)){\n          mySimpit.activateAction(GEAR_ACTION);\n        }\n        if(!(Analog[0] & 64) && (currentActionStatus & GEAR_ACTION)){\n          mySimpit.deactivateAction(GEAR_ACTION);\n        }\n      }\n\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setKey(Analog[0] & 1, Analog_Trim, Analog_flag[0]);\n      setKey(Analog[0] & 2, Analog_Reset_Trim, Analog_flag[1]);\n      setKey(Analog[0] & 4, Analog_Brakes, Analog_flag[2]);\n      setKey_Switch(Analog[0] & 8, Analog_RVR, Analog_flag[3]);\n      setKey_Switch(Analog[0] & 16, Analog_PLN, Analog_flag[4]);\n      setKey_Switch(Analog[0] & 32, Analog_TRN, Analog_flag[5]);\n      setKey_Switch(Analog[0] & 64, Analog_Gear, Analog_flag[6]);\n    }\n    Analog_LAST = Analog_STATE;\n  }\n\n  // Rotation \n  if (!keyboardEmulation) {\n    if (analog_mode == 1) {\n      // Plane\n      if (vehicleType == 0) {\n        updateAnalogValues(ANALOG_ROTATION_MESSAGE, Analog_axis2, Analog_axis1, Analog_axis0);\n        updateAnalogValues(ANALOG_WHEEL_MESSAGE, Analog_axis1_wheels, Analog_axis0_wheels, 0);\n    \n        // Trim\n        if (Analog[0] & 1) {\n          trimy = Analog_axis2;\n          trimp = Analog_axis1;\n          trimr = Analog_axis0;\n        }\n        updateAnalogValues(ANALOG_ROTATION_MESSAGE, checkTrim(trimy, Analog_axis2), checkTrim(trimp, Analog_axis1), checkTrim(trimr, Analog_axis0));\n      }\n      \n      // Rocket\n      if (vehicleType == 1) {\n        updateAnalogValues(ANALOG_ROTATION_MESSAGE, Analog_axis0, Analog_axis1, Analog_axis2);\n        updateAnalogValues(ANALOG_WHEEL_MESSAGE, 0, 0, 0);\n      }\n      \n      // Rover\n      if (vehicleType == 2) {\n        updateAnalogValues(ANALOG_ROTATION_MESSAGE, Analog_axis2, Analog_axis1, Analog_axis0);\n      }\n      updateAnalogValues(ANALOG_TRANSLATION_MESSAGE, 0, 0, 0);\n    }\n\n    // Translation\n    if (analog_mode == 0) {\n      \n      updateAnalogValues(ANALOG_TRANSLATION_MESSAGE, Analog_axis0, Analog_axis1, Analog_axis2);\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, 0, 0, 0);\n      \n      // Rover\n      if (vehicleType == 2) {\n        // Cruise\n        if (Analog[0] & 1) {\n          cruise_control = Analog_axis1_wheels;\n        }\n        if ((cruise_control != 0) and (Analog_axis1_wheels <= cruise_control)) {\n          myWheel.throttle = cruise_control;\n        } else {\n          myWheel.throttle = Analog_axis1_wheels;\n        }\n        myWheel.steer = Analog_axis0_wheels;\n      }\n    }\n    // Execute (send only when value changed)\n    sendRotationIfChanged();\n    sendTranslationIfChanged();\n    if (Analog_Throttle_Con) {\n      sendThrottleIfChanged(Rotation_throttle, Rotation_throttleOld);\n    }\n    sendWheelIfChanged();\n    \n  } else {\n    // Yaw (axis2), Pitch (axis1), Roll (axis0)\n    setAnalogAxisKey(Analog_axis2, deadZone_max, true, Analog_Twist_Right, Analog_flag[7]);\n    setAnalogAxisKey(Analog_axis2, deadZone_min, false, Analog_Twist_Left, Analog_flag[8]);\n    setAnalogAxisKey(Analog_axis1, deadZone_max, true, Analog_Forward, Analog_flag[9]);\n    setAnalogAxisKey(Analog_axis1, deadZone_min, false, Analog_Backward, Analog_flag[10]);\n    setAnalogAxisKey(Analog_axis0, deadZone_max, true, Analog_Left, Analog_flag[11]);\n    setAnalogAxisKey(Analog_axis0, deadZone_min, false, Analog_Right, Analog_flag[12]);\n  }\n}\n\n// Keyboard Emulation\n  #define Analog_Trim                         ':'\n  #define Analog_Reset_Trim                   '?'\n  #define Analog_Brakes                       'b'\n  #define Analog_Gear                         'g'\n  #define Analog_RVR                          '3'\n  // RKT mode is not actually an input\n  #define Analog_PLN                          '5'\n  #define Analog_TRN                          '6'\n  // ROT mode is not actually an input\n  #define Analog_Twist_Right                  'w'\n  #define Analog_Twist_Left                   's'\n  #define Analog_Forward                      'a'\n  #define Analog_Backward                     'd'\n  #define Analog_Left                         'q'\n  #define Analog_Right                        'e'","f3.ino":"// Transmissions\nif (Rotation_Con) {module_transmission(Rotation_, Rotation, 7, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Rotation_Con){Rotation_Action();}\n\n// Action\nvoid Rotation_Action() {\n  if (Rotation[0] != Rotation_STATE) {\n    Rotation_STATE = Rotation[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if ((Rotation[0] & 1) && !(currentActionStatus & LIGHT_ACTION)){\n        mySimpit.activateAction(LIGHT_ACTION);\n      }\n      if ((Rotation[0] & 1) && (currentActionStatus & LIGHT_ACTION)){\n        mySimpit.deactivateAction(LIGHT_ACTION);\n      }\n      if (Rotation[0] & 2) {\n        trimy = 0;\n        trimp = 0;\n        trimr = 0;\n      }\n      if (Rotation[0] & 4) {\n        Trim_On = true;\n      } else {\n        Trim_On = false;\n      }\n      if (Rotation[0] & 8) {\n        vehicleType = rover;\n      } else if (Rotation[0] & 16) {\n        vehicleType = plane;\n      } else {\n        vehicleType = rocket;\n      }\n      if((Rotation[0] & 32) && !(currentActionStatus & GEAR_ACTION)){\n        mySimpit.activateAction(GEAR_ACTION);\n      }\n      if(!(Rotation[0] & 32) && (currentActionStatus & GEAR_ACTION)){\n        mySimpit.deactivateAction(GEAR_ACTION);\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setSimpitAction(Rotation[0] & 1, Rotation_Light, Rotation_flag[0], tapKey);\n      setSimpitAction(Rotation[0] & 2, Rotation_Reset_Trim, Rotation_flag[1], tapKey);\n      setSimpitAction(Rotation[0] & 4, Rotation_Trim, Rotation_flag[2], tapKey);\n      setSimpitAction_Switch(Rotation[0] & 8, Rotation_RVR, Rotation_flag[3], tapKey, tapKey);\n      setSimpitAction_Switch(Rotation[0] & 16, Rotation_PLN, Rotation_flag[4], tapKey, tapKey);\n      setSimpitAction_Switch(Rotation[0] & 32, Rotation_Gear, Rotation_flag[5], tapKey, tapKey);\n    }\n    Rotation_LAST = Rotation_STATE;\n  }\n\n  if (!keyboardEmulation) {\n    // Plane\n    if (vehicleType == 0) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, Rotation_axis2, Rotation_axis1, Rotation_axis0);\n      updateAnalogValues(ANALOG_WHEEL_MESSAGE, Rotation_axis1_wheels, Rotation_axis0_wheels, 0);\n\n      // Trim\n      if (Trim_On) {\n        trimy = Rotation_axis2;\n        trimp = Rotation_axis1;\n        trimr = Rotation_axis0;\n      }\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, checkTrim(trimy, Rotation_axis2), checkTrim(trimp, Rotation_axis1), checkTrim(trimr, Rotation_axis0));\n    }\n    \n    // Rocket\n    if (vehicleType == 1) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, Rotation_axis0, Rotation_axis1, Rotation_axis2);\n      updateAnalogValues(ANALOG_WHEEL_MESSAGE, 0, 0, 0);\n    }\n    \n    // Rover\n    if (vehicleType == 2) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, Rotation_axis2, Rotation_axis1, Rotation_axis0);\n    }\n\n    if (precision) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, myRotation.yaw/prec_divide, myRotation.pitch/prec_divide, myRotation.roll/prec_divide);\n    }\n\n    // Execute\n    //sendRotationIfChanged();\n    if (memcmp(&myRotation, &myRotationOld, sizeof(rotationMessage)) != 0) {\n      mySimpit.send(ROTATION_MESSAGE, myRotation);\n      myRotationOld = myRotation;\n    }\n\n    sendWheelIfChanged();\n  } else {\n    setKey(Rotation_axis2 > keyboardEmulation_threshold, Rotation_Twist_Right, Rotation_flag[6]);\n    setKey(Rotation_axis2 < -keyboardEmulation_threshold, Rotation_Twist_Left, Rotation_flag[7]);\n    setKey(Rotation_axis1 > keyboardEmulation_threshold, Rotation_Backward, Rotation_flag[8]);\n    setKey(Rotation_axis1 < -keyboardEmulation_threshold, Rotation_Forward, Rotation_flag[9]);\n    setKey(Rotation_axis0 > keyboardEmulation_threshold, Rotation_Right, Rotation_flag[10]);\n    setKey(Rotation_axis0 < -keyboardEmulation_threshold, Rotation_Left, Rotation_flag[11]);\n  }\n}\n\n// Keyboard Emulation\n  #define Rotation_Gear                       'g'\n  #define Rotation_Light                      'u'\n  #define Rotation_Reset_Trim                 '?'\n  #define Rotation_Trim                       ':'\n  #define Rotation_PLN                        '3'\n  // RKT mode is not actually an input\n  #define Rotation_RVR                        '5'\n  #define Rotation_Forward                    'w'\n  #define Rotation_Backward                   's'\n  #define Rotation_Left                       'a'\n  #define Rotation_Right                      'd'\n  #define Rotation_Twist_Left                 'q'\n  #define Rotation_Twist_Right                'e'","f4.ino":"// Transmissions\nif (Rotation_Throttle_Con) {module_transmission(Rotation_Throttle_, Rotation, 9, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Rotation_Throttle_Con){Rotation_Throttle_Action();}\n\n// Action\nvoid Rotation_Throttle_Action() {\n  if (Rotation[0] != Rotation_Throttle_STATE) {\n    Rotation_Throttle_STATE = Rotation[0];\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (Rotation[0] & 1) {\n        Trim_On = true;\n      } else {\n        Trim_On = false;\n      }\n      if (Rotation[0] & 2) {\n        vehicleType = rover;\n      } else if (Rotation[0] & 4) {\n        vehicleType = plane;\n      } else {\n        vehicleType = rocket;\n      }\n      if (Rotation[0] & 8) {\n        trimy = 0;\n        trimp = 0;\n        trimr = 0;\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setSimpitAction(Rotation[0] & 1, Rotation_Throttle_Trim, Rotation_Throttle_flag[0], tapKey);\n      setSimpitAction_Switch(Rotation[0] & 2, Rotation_Throttle_RVR, Rotation_Throttle_flag[1], tapKey, tapKey);\n      setSimpitAction_Switch(Rotation[0] & 4, Rotation_Throttle_PLN, Rotation_Throttle_flag[2], tapKey, tapKey);\n      setSimpitAction(Rotation[0] & 8, Rotation_Throttle_Reset_Trim, Rotation_Throttle_flag[3], tapKey);\n    }\n    Rotation_Throttle_LAST = Rotation_Throttle_STATE;\n  }\n\n  if (!keyboardEmulation) {\n    // Plane\n    if (vehicleType == 0) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, Rotation_axis2, Rotation_axis1, Rotation_axis0);\n      updateAnalogValues(ANALOG_WHEEL_MESSAGE, Rotation_axis1_wheels, Rotation_axis0_wheels, 0);\n\n      // Trim\n      if (Trim_On) {\n        trimy = Rotation_axis2;\n        trimp = Rotation_axis1;\n        trimr = Rotation_axis0;\n      }\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, checkTrim(trimy, Rotation_axis2), checkTrim(trimp, Rotation_axis1), checkTrim(trimr, Rotation_axis0));\n    }\n    \n    // Rocket\n    if (vehicleType == 1) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, Rotation_axis0, Rotation_axis1, Rotation_axis2);\n      updateAnalogValues(ANALOG_WHEEL_MESSAGE, 0, 0, 0);\n    }\n    \n    // Rover\n    if (vehicleType == 2) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, Rotation_axis2, Rotation_axis1, Rotation_axis0);\n    }\n\n    if (precision) {\n      updateAnalogValues(ANALOG_ROTATION_MESSAGE, myRotation.yaw/prec_divide, myRotation.pitch/prec_divide, myRotation.roll/prec_divide);\n    }\n\n    // Execute\n    //sendRotationIfChanged();\n    if (memcmp(&myRotation, &myRotationOld, sizeof(rotationMessage)) != 0) {\n      mySimpit.send(ROTATION_MESSAGE, myRotation);\n      myRotationOld = myRotation;\n    }\n    if (Rotation_Throttle_Con) {\n      sendThrottleIfChanged(Rotation_throttle, Rotation_throttleOld);\n    }\n\n    sendWheelIfChanged();\n  } else {\n    setKey(Rotation_axis2 > keyboardEmulation_threshold, Rotation_Throttle_Twist_Right, Rotation_Throttle_flag[6]);\n    setKey(Rotation_axis2 < -keyboardEmulation_threshold, Rotation_Throttle_Twist_Left, Rotation_Throttle_flag[7]);\n    setKey(Rotation_axis1 > keyboardEmulation_threshold, Rotation_Throttle_Backward, Rotation_Throttle_flag[8]);\n    setKey(Rotation_axis1 < -keyboardEmulation_threshold, Rotation_Throttle_Forward, Rotation_Throttle_flag[9]);\n    setKey(Rotation_axis0 > keyboardEmulation_threshold, Rotation_Throttle_Right, Rotation_Throttle_flag[10]);\n    setKey(Rotation_axis0 < -keyboardEmulation_threshold, Rotation_Throttle_Left, Rotation_Throttle_flag[11]);\n    setKey(Rotation_throttle > keyboardEmulation_threshold, Rotation_Throttle_Throttle, Rotation_Throttle_flag[12]);\n  }\n}\n\n// Keyboard Emulation\n  #define Rotation_Throttle_Throttle          '1'\n  #define Rotation_Throttle_Reset_Trim        '?'\n  #define Rotation_Throttle_Trim              ':'\n  #define Rotation_Throttle_PLN               '3'\n  // RKT mode is not actually an input\n  #define Rotation_Throttle_RVR               '5'\n  #define Rotation_Throttle_Forward           'w'\n  #define Rotation_Throttle_Backward          's'\n  #define Rotation_Throttle_Left              'a'\n  #define Rotation_Throttle_Right             'd'\n  #define Rotation_Throttle_Twist_Left        'q'\n  #define Rotation_Throttle_Twist_Right       'e'","f5.ino":"// Transmissions\nif (Translation_Con) {module_transmission(Translation_, Translation, 9, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Translation_Con){Translation_Action();}\n\n// Action Results\nuint8_t EVA_List_Analog[10] = {\n  'b',\n  'f',\n  ' ',\n  'r',\n  KEY_LEFT_SHIFT,\n  KEY_LEFT_CTRL,\n  'w',\n  'a',\n  's',\n  'd',\n};\n\n// Action\nvoid Translation_Action() {\n  if (Translation[0] != Translation_STATE) {\n    Translation_STATE = Translation[0];\n  \n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (On_EVA and !EVA_Ctrl_Con) {\n        setKey(Translation[0] & 8, EVA_List_Analog[2], EVA_flag[6]);\n        setKey(Translation[0] & 1, EVA_List_Analog[1], EVA_flag[7]);\n        setKey(Translation[0] & 16, EVA_List_Analog[0], EVA_flag[8]);\n        setKey_Switch(Translation[0] & 2, EVA_List_Analog[3], EVA_flag[9]);\n      } else {\n        // Precision Control\n        if (Translation[0] & 2) {\n          precision = true;\n        } else {\n          precision = false;\n        }\n      \n        // Parking Break On\n        if ((Translation[0] & 4) and !parking_break){\n          mySimpit.activateAction(BRAKES_ACTION);\n          parking_break = true;\n          cruise_control = 0;\n        }\n      \n        // Parking Break Off\n        if(!(Translation[0] & 4) && !brakes_pushed && parking_break){\n          mySimpit.deactivateAction(BRAKES_ACTION);\n          parking_break = false;\n        }\n      \n        // Brakes\n        if((Translation[0] & 8) && !brakes_pushed && !parking_break){\n          mySimpit.activateAction(BRAKES_ACTION);\n          cruise_control = 0;\n          brakes_pushed = true;\n        }\n        if(!(Translation[0] & 8) && brakes_pushed){\n          brakes_pushed = false;\n          if (!parking_break) {\n            mySimpit.deactivateAction(BRAKES_ACTION);\n          }\n        }\n      \n        // Reset Cruise\n        if (Translation[0] & 16) {\n          cruise_control = 0;\n        }\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setSimpitAction(Translation[0] & 1, Translation_Cruise, Translation_flag[4], tapKey);\n      setSimpitAction_Switch(Translation[0] & 2, Translation_Precision_Control, Translation_flag[0], tapKey, tapKey);\n      setSimpitAction_Switch(Translation[0] & 4, Translation_Brakes_Lock, Translation_flag[1], tapKey, tapKey);\n      setSimpitAction(Translation[0] & 8, Translation_Brakes, Translation_flag[2], tapKey);\n      setSimpitAction(Translation[0] & 16, Translation_Reset_Cruise, Translation_flag[3], tapKey);\n    }\n    Translation_LAST = Translation_STATE;Translation_LAST = Translation_STATE;\n  }\n  if (!keyboardEmulation) {\n    if (vehicleType != rover) {\n      if (precision) {\n        updateAnalogValues(ANALOG_TRANSLATION_MESSAGE, Translation_axis0/prec_divide, Translation_axis1/prec_divide, Translation_axis2/prec_divide);\n      } else {\n        updateAnalogValues(ANALOG_TRANSLATION_MESSAGE, Translation_axis0, Translation_axis1, Translation_axis2);\n      }\n    } else {\n      // Set Cruise Control and Wheel Throttle/Steering\n      if (Translation[0] & 1) {\n        cruise_control = Translation_axis1_wheels;\n      }\n      if ((cruise_control != 0) and (Translation_axis1_wheels <= cruise_control)) {\n        myWheel.throttle = cruise_control;\n      } else {\n        myWheel.throttle = Translation_axis1_wheels;\n      }\n      myWheel.steer = Translation_axis0_wheels;\n    }\n\n    // Execute\n    sendTranslationIfChanged();\n    sendWheelIfChanged();\n  } else {\n    if (On_EVA and !EVA_Ctrl_Con) {\n      setKey(Translation_axis0 < 0, EVA_List_Analog[9], EVA_flag[0]);\n      setKey(Translation_axis0 > 0, EVA_List_Analog[7], EVA_flag[1]);\n      setKey(Translation_axis2 < 0, EVA_List_Analog[4], EVA_flag[2]);\n      setKey(Translation_axis2 > 0, EVA_List_Analog[5], EVA_flag[3]);\n      setKey(Translation_axis1 < 0, EVA_List_Analog[6], EVA_flag[4]);\n      setKey(Translation_axis1 > 0, EVA_List_Analog[8], EVA_flag[5]);\n    } else {\n      setKey(Translation_axis2 > keyboardEmulation_threshold, Translation_Twist_Left, Translation_flag[6]);\n      setKey(Translation_axis2 < -keyboardEmulation_threshold, Translation_Twist_Right, Translation_flag[7]);\n      setKey(Translation_axis1 > keyboardEmulation_threshold, Translation_Backward, Translation_flag[8]);\n      setKey(Translation_axis1 < -keyboardEmulation_threshold, Translation_Forward, Translation_flag[9]);\n      setKey(Translation_axis0 > keyboardEmulation_threshold, Translation_Left, Translation_flag[10]);\n      setKey(Translation_axis0 < -keyboardEmulation_threshold, Translation_Right, Translation_flag[11]);\n    }\n  }\n}\n\n// Keyboard Emulation\n  #define Translation_Brakes                  'b'\n  #define Translation_Brakes_Lock             'b'\n  #define Translation_Cruise                  '8'\n  #define Translation_Reset_Cruise            '9'\n  #define Translation_Precision_Control       '0'\n  #define Translation_Forward                 'i'\n  #define Translation_Backward                'k'\n  #define Translation_Left                    'j'\n  #define Translation_Right                   'l'\n  #define Translation_Twist_Left              'h'\n  #define Translation_Twist_Right             'n'","f6.ino":"// Transmissions\nif (Throttle_Con) {module_transmission(Throttle_, Throttle, 3, NO_DISPLAY, NO_DISPLAY, NO_DISPLAY);}\n\n// Enable Action\nif (Throttle_Con){Throttle_Action();}\n\n// Action\nvoid Throttle_Action() {\n  if (Throttle[0] != Throttle_STATE) {\n    Throttle_STATE = Throttle[0];\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      if (Throttle[0] & 1) {\n        throttle_pcont = true;\n      } else {\n        throttle_pcont = false;\n      }\n      if (Throttle[0] & 2) {\n        throttle = 0;\n      }\n      sendThrottleIfChanged(throttle, throttleOld);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      setSimpitAction_Switch(Throttle[0] & 1, Throttle_Precision, Throttle_flag[0], tapKey, tapKey);\n      setSimpitAction(Throttle[0] & 2, Throttle_Min, Throttle_flag[1], tapKey);\n      setKey(throttle > throttle_min+100, Throttle_Forward, Throttle_flag[2]);\n    }\n  }\n  Throttle_LAST = Throttle_STATE;\n}\n\n// Keyboard Emulation\n  #define Throttle_Precision                  '1'\n  #define Throttle_Min                        '2'\n  // Throttle Max is not actually an input\n  #define Throttle_Forward                    '0'\n","g1.ino":"// Transmissions\nif (Ctrl_Sys_Ctrl_Con) {module_transmission(Ctrl_Sys_Ctrl_, Ctrl_Sys_Ctrl, TWO_BYTES, Ctrl_Sys_Dspl_, Ctrl_Sys_Dspl, ONE_BYTE);}\n\n// Enable Action\nif (Ctrl_Sys_Ctrl_Con){Ctrl_Sys_Action();}\n\n// Action Results\nAutopilotMode SASMode[10] = {\n  AP_MANEUVER,\n  AP_STABILITYASSIST,\n  AP_RETROGRADE,\n  AP_PROGRADE,\n  AP_ANTINORMAL,\n  AP_NORMAL,\n  AP_RADIALOUT,\n  AP_RADIALIN,\n  AP_ANTITARGET,\n  AP_TARGET,\n};\n\n// Action\nvoid Ctrl_Sys_Action() {\n  ControlSys_combinedBytes = Ctrl_Sys_Ctrl[0] + (Ctrl_Sys_Ctrl[1]*256);\n  if (ControlSys_combinedBytes != Ctrl_Sys_STATE) {\n    Ctrl_Sys_STATE = ControlSys_combinedBytes;\n\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      for (int i = 0; i < 10; i++) {\n        setSimpitAction(Ctrl_Sys_STATE & 1<<i, SASMode[i], Ctrl_Systems_flag[i], simpitSetSASMode);\n      }\n      setSimpitAction_Switch(Ctrl_Sys_STATE & 1024, SAS_ACTION, Ctrl_Systems_flag[10], simpitActivateAction, simpitDeactivateAction);\n      setSimpitAction_Switch(Ctrl_Sys_STATE & 2048, RCS_ACTION, Ctrl_Systems_flag[11], simpitActivateAction, simpitDeactivateAction);\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 10; i++) {\n        setKey(Ctrl_Sys_STATE & 1<<i, Control_Systems_Emulation_Keys[i], Ctrl_Systems_flag[i]);\n      }\n      setKey_Switch(Ctrl_Sys_STATE & 1024, Control_Systems_SAS, Ctrl_Systems_flag[10]);\n      setKey_Switch(Ctrl_Sys_STATE & 2048, Control_Systems_RCS, Ctrl_Systems_flag[11]);\n    }\n  }\n  Ctrl_Sys_LAST = Ctrl_Sys_STATE;\n}\n\n// Message Handler\n    case SAS_MODE_INFO_MESSAGE:\n      if (Ctrl_Sys_Ctrl_Con or EA_Control_Ctrl_Con) {\n        if (msgSize == sizeof(SASInfoMessage)) {\n          SASInfoMessage mySAS;\n          mySAS = parseSASInfoMessage(msg);\n          bool stabAssist = (mySAS.currentSASMode==AP_STABILITYASSIST);\n          bitWrite(EA_Control_Dspl[0], 3, stabAssist);\n          if (ControlSys_combinedBytes & 1024) {\n            Ctrl_Sys_Dspl[0] = mySAS.currentSASMode;\n          } else {\n            Ctrl_Sys_Dspl[0] = 11;\n          }\n        }\n      }\n      break;\n\n// Keyboard Emulation\n  #define Control_Systems_Hold                '1'\n  #define Control_Systems_Maneuver            '2'\n  #define Control_Systems_Prograde            '3'\n  #define Control_Systems_Retrograde          '4'\n  #define Control_Systems_Normal              '5'\n  #define Control_Systems_AntiNormal          '6'\n  #define Control_Systems_RadialOut           '7'\n  #define Control_Systems_RadialIn            '8'\n  #define Control_Systems_TargetPrograde      '9'\n  #define Control_Systems_TargetRetrograde    '0'\n  #define Control_Systems_SAS                 't'\n  #define Control_Systems_RCS                 'r'\n\n// definitions\n  const uint8_t Control_Systems_Emulation_Keys[12] = {\n    Control_Systems_Maneuver,\n    Control_Systems_Hold,\n    Control_Systems_Retrograde,\n    Control_Systems_Prograde,\n    Control_Systems_AntiNormal,\n    Control_Systems_Normal,\n    Control_Systems_RadialOut,\n    Control_Systems_RadialIn,\n    Control_Systems_TargetRetrograde,\n    Control_Systems_TargetPrograde,\n  };","h1.ino":"// Transmissions\nif (Action_Ctrl_Con) {module_transmission(Action_Ctrl_, Action_Ctrl, TWO_BYTES, Action_Dspl_, Action_Dspl, TWO_BYTES);}\n\n// Enable Action\nif (Action_Ctrl_Con){Action_Action();}\n\n// Action Results\nconst int AG_List[10] = {1,6,2,7,3,8,4,9,5,10};\n\n// Action\nvoid Action_Action() {\n  int Action_combinedBytes = Action_Ctrl[0] + (Action_Ctrl[1]*256);\n  if (Action_combinedBytes != Action_STATE) {\n    Action_STATE = Action_combinedBytes;\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      for (int i = 0; i < 10; i++) {\n        setSimpitAction(Action_STATE & 1<<i, AG_List[i], Action_flag[i], simpitToggleCAG);\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 10; i++) {\n        setKey(Action_STATE & 1<<i, Action_Emulation_Keys[i], Action_flag[i]);\n      }\n    }\n\n  }\n  Action_LAST = Action_STATE;\n}\n\n// Message Handler\n          if (Action_Ctrl_Con) {\n            bool Action_Dspl_b[10] = {};\n            for (int i = 0; i < 10; i++) {\n              Action_Dspl_b[i] = (myAG.is_action_activated(AG_List[i]));\n            }\n            for (int i = 0; i < 8; i++) {\n              bitWrite(Action_Dspl[0], i, Action_Dspl_b[i]);\n            }\n            for (int i = 0; i < 2; i++) {\n              bitWrite(Action_Dspl[1], i, Action_Dspl_b[i+8]);\n            }\n          }\n\n// Keyboard Emulation\n  #define Action_Group_1                      '1'\n  #define Action_Group_2                      '2'\n  #define Action_Group_3                      '3'\n  #define Action_Group_4                      '4'\n  #define Action_Group_5                      '5'\n  #define Action_Group_6                      '6'\n  #define Action_Group_7                      '7'\n  #define Action_Group_8                      '8'\n  #define Action_Group_9                      '9'\n  #define Action_Group_10                     '0'\n\n// definitions\n  const uint8_t Action_Emulation_Keys[10] = {\n    Action_Group_1,\n    Action_Group_6,\n    Action_Group_2,\n    Action_Group_7,\n    Action_Group_3,\n    Action_Group_8,\n    Action_Group_4,\n    Action_Group_9,\n    Action_Group_5,\n    Action_Group_10,\n  };","h2.ino":"// Transmissions\nif (Action2_Ctrl_Con) {module_transmission(Action2_Ctrl_, Action2_Ctrl, TWO_BYTES, Action2_Dspl_, Action2_Dspl, TWO_BYTES);}\n\n// Enable Action\nif (Action2_Ctrl_Con){Action2_Action();}\n\n// Action Results\nconst int AG2_List[10] = {11,16,12,17,13,18,14,19,15,20};\n\n// Action\nvoid Action2_Action() {\n  int Action2_combinedBytes = Action2_Ctrl[0] + (Action2_Ctrl[1]*256);\n  if (Action2_combinedBytes != Action2_STATE) {\n    Action2_STATE = Action2_combinedBytes;\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      for (int i = 0; i < 10; i++) {\n        setSimpitAction(Action2_STATE & 1<<i, AG2_List[i], Action2_flag[i], simpitToggleCAG);\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 10; i++) {\n        setKey(Action2_STATE & 1<<i, Action2_Emulation_Keys[i], Action2_flag[i]);\n      }\n    }\n  }\n  Action2_LAST = Action2_STATE;\n}\n\n// Message Handler\n          if (Action2_Ctrl_Con) {\n            bool Action2_Dspl_b[10] = {};\n            for (int i = 0; i < 10; i++) {\n              Action2_Dspl_b[i] = (myAG.is_action_activated(AG2_List[i]));\n            }\n            for (int i = 0; i < 8; i++) {\n              bitWrite(Action2_Dspl[0], i, Action2_Dspl_b[i]);\n            }\n            for (int i = 0; i < 2; i++) {\n              bitWrite(Action2_Dspl[1], i, Action2_Dspl_b[i+8]);\n            }\n          }\n\n// Keyboard Emulation\n  #define Action_Group_11                     '1'\n  #define Action_Group_12                     '2'\n  #define Action_Group_13                     '3'\n  #define Action_Group_14                     '4'\n  #define Action_Group_15                     '5'\n  #define Action_Group_16                     '6'\n  #define Action_Group_17                     '7'\n  #define Action_Group_18                     '8'\n  #define Action_Group_19                     '9'\n  #define Action_Group_20                     '0'\n\n// definitions\n  const uint8_t Action2_Emulation_Keys[10] = {\n    Action_Group_11,\n    Action_Group_16,\n    Action_Group_12,\n    Action_Group_17,\n    Action_Group_13,\n    Action_Group_18,\n    Action_Group_14,\n    Action_Group_19,\n    Action_Group_15,\n    Action_Group_20,\n  };","h3.ino":"// Transmissions\nif (Action3_Ctrl_Con) {module_transmission(Action3_Ctrl_, Action3_Ctrl, TWO_BYTES, Action3_Dspl_, Action3_Dspl, TWO_BYTES);}\n\n// Enable Action\nif (Action3_Ctrl_Con){Action3_Action();}\n\n// Action Results\nconst int AG3_List[10] = {21,26,22,27,23,28,24,29,25,30};\n\n// Action\nvoid Action3_Action() {\n  int Action3_combinedBytes = Action3_Ctrl[0] + (Action3_Ctrl[1]*256);\n  if (Action3_combinedBytes != Action3_STATE) {\n    Action3_STATE = Action3_combinedBytes;\n    if (!keyboardEmulation) {\n      // Controller is in KSP mode\n      for (int i = 0; i < 10; i++) {\n        setSimpitAction(Action3_STATE & 1<<i, AG3_List[i], Action3_flag[i], simpitToggleCAG);\n      }\n    } else {\n      // Controller is in Keyboard Emulation mode\n      for (int i = 0; i < 10; i++) {\n        setKey(Action3_STATE & 1<<i, Action3_Emulation_Keys[i], Action3_flag[i]);\n      }\n    }\n  }\n  Action2_LAST = Action2_STATE;\n}\n\n// Message Handler\n          if (Action3_Ctrl_Con) {\n            bool Action3_Dspl_b[10] = {};\n            for (int i = 0; i < 10; i++) {\n              Action3_Dspl_b[i] = (myAG.is_action_activated(AG3_List[i]));\n            }\n            for (int i = 0; i < 8; i++) {\n              bitWrite(Action3_Dspl[0], i, Action3_Dspl_b[i]);\n            }\n            for (int i = 0; i < 2; i++) {\n              bitWrite(Action3_Dspl[1], i, Action3_Dspl_b[i+8]);\n            }\n          }\n\n// Keyboard Emulation\n  #define Action_Group_21                     '1'\n  #define Action_Group_22                     '2'\n  #define Action_Group_23                     '3'\n  #define Action_Group_24                     '4'\n  #define Action_Group_25                     '5'\n  #define Action_Group_26                     '6'\n  #define Action_Group_27                     '7'\n  #define Action_Group_28                     '8'\n  #define Action_Group_29                     '9'\n  #define Action_Group_30                     '0'\n\n// definitions\n  const uint8_t Action3_Emulation_Keys[10] = {\n    Action_Group_21,\n    Action_Group_26,\n    Action_Group_22,\n    Action_Group_27,\n    Action_Group_23,\n    Action_Group_28,\n    Action_Group_24,\n    Action_Group_29,\n    Action_Group_25,\n    Action_Group_30,\n  };"};
